var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그림자라는 거... 꽤 맛있네. 론 리.","JPN":"シャドウって……結構おいしいね、ローン・リー。","ENG":"These Shadows... are quite tasty, Lone Lee.","TWN":"這些所謂的暗影……還挺好吃的嘛，隆利。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그러엄- 내가 말했지?","JPN":"そうだよ～だから言ったでしょう？","ENG":"See? I told you.","TWN":"當然—我早就說過了吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"죽은 그림자를 흡수해서 산 그림자를 해치우는 침식체라니. 무한동력이네요.","JPN":"死んだシャドウを吸収して生きたシャドウを倒す侵食体とは、まさに永久機関ですね。","ENG":"A C.O. that absorbs dead Shadows to take down living ones. That's practically an infinite power source.","TWN":"能吸收死去的暗影、再吞噬活著的暗影的侵蝕體，根本就是無限動力。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"침식체치곤 제법 귀엽기도 하고요.","JPN":"侵食体にしてはなかなかかわいらしい外見をしていますし。","ENG":"And for a C.O., she's pretty cute too.","TWN":"而且以侵蝕體來說還挺可愛的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래? 난 저런 꼬리가 달린 건 좀 징그러운데.","JPN":"そう？　私はああいう尻尾がついてるのはちょっと気持ち悪いかな。","ENG":"Really? I think anything with a tail like that is kind of creepy.","TWN":"是嗎？我倒覺得那種長著尾巴的東西有點噁心。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그나저나...","JPN":"それより……","ENG":"Anyway...","TWN":"話說……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석 눈빛이 점점 변하고 있지 않아?","JPN":"あいつ、だんだん目つきが変わってきてない？","ENG":"Isn't her gaze starting to change?","TWN":"那傢伙的眼神好像越來越不對勁了吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"킥킥킥...","JPN":"キキキッ……","ENG":"Kehehe...","TWN":"嘻嘻嘻……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"이렇게 많은 힘이 있으면... 더 맛있는 것도 먹을 수 있어.","JPN":"これだけの力があれば……もっと美味しいものも食べられる。","ENG":"With this much power... I can eat something even more delicious.","TWN":"既然有這麼多力量……就能吃到更美味的東西了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄앗!","JPN":"きゃあっ！","ENG":"Kyaah!","TWN":"呀啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그 중에서도... 네가 최고로 맛있어 보여.","JPN":"その中でも……あなたがいちばん美味しそう。","ENG":"You look... the most tasty.","TWN":"尤其是……你看起來最美味。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엣, 맛있어 보인다니. 살면서 그런 말은 처음 들어봐요.","JPN":"えっ、美味しそうって。そんなこと言われたのは生まれて初めてです。","ENG":"\\"Tasty\\"? I've never been told that before in my entire life.","TWN":"欸，我這輩子還是第一次被說看起來很好吃。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배, 이럴 땐 어떻게 대답해야 하는 거죠?","JPN":"ミナ先輩、こういう時はどう答えたらいいですか？","ENG":"Mina, how am I supposed to respond to something like that?","TWN":"米娜前輩，這種時候該怎麼回啊？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"지금 그런 걸 물어볼 때가 아니잖아! 내가 처리할 테니 물러서!","JPN":"そんなこと聞いてる場合じゃないでしょ！　私が片付けるから下がって！","ENG":"This isn't the time to be asking that! I'll handle it, so get back!","TWN":"現在是問這種事的時候嗎！我來處理，你快退後！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"윽, 저도 떨쳐내고 싶은데... 힘이 너무 강해요...!","JPN":"うっ、私もそうしたいんですけど……力が強すぎます……！","ENG":"Ugh, I want to shake her off too... but she's too strong...!","TWN":"唔，我也想掙脫……可是這力道太大了……！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"그럼-","JPN":"じゃあ……","ENG":"Then...","TWN":"那就—"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_NULL","text":{"KOREA":"잘 먹겠습니다...!","JPN":"いただきま～す……！","ENG":"Bon appetit...!","TWN":"我開動了……！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으앙, 싫어어!","JPN":"わーん、助けてええ！","ENG":"Waah, nooo!","TWN":"不要啊啊啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"확실히 골칫거리를 한 곳에 모아두니 처리하기 편리하군.","JPN":"確かに、厄介者を1か所に集めると処理しやすいな。","ENG":"It certainly makes things easier to handle when all the trouble is gathered in one place.","TWN":"果然，把麻煩的東西集中在一起處理起來方便多了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 그림자의 힘을 삼킨 침식체도 스승님 꿀밤은 감당하지 못하는군요.","JPN":"ハハ、シャドウの力を呑み込んだ侵食体も、師匠の拳には敵わないんですね。","ENG":"Haha, even a C.O. that swallowed a Shadow's power can't withstand Master's knuckle strike.","TWN":"哈哈，連吞下暗影力量的侵蝕體，也撐不住師父的一記爆擊啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐으... 놀랐다아.","JPN":"ふう……びっくりした。","ENG":"Hngh... that startled me.","TWN":"呼……嚇死我了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"앞으로도 급할 땐 제법 요긴하겠어.","JPN":"これからも急を要する時は重宝しそうだ。","ENG":"This could be quite useful in emergencies from now on.","TWN":"以後緊急時應該還挺好用的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너, 이 녀석을 잘 간수하도록.","JPN":"お前、こいつの管理はちゃんとするように。","ENG":"You, make sure to keep a close watch on this one.","TWN":"你好好看著這傢伙。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"네, 넵!","JPN":"は、はいっ！","ENG":"Y-yes, ma'am!","TWN":"是、是！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"함선이 왜 이렇게 흔들리지? 설마 터널이 무너지려는 건가?","JPN":"なんで艦船がこんなに揺れるんだろう？　まさかトンネルが崩れるんじゃないよね？","ENG":"Why is the ship shaking like this? Is the tunnel about to collapse?","TWN":"艦船怎麼這麼晃？難道隧道要塌了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"목적지에 거의 도달했다는 뜻이야. 터널이 연결하는 두 지점의 기압차가 클수록 출입구의 바람이 거세지는 것과 비슷한 원리지.","JPN":"目的地が近いってことさ。トンネルが繋いでいる両地点の気圧差が大きくなる程、出入り口の風が強くなるのと同じ原理だよ。","ENG":"It means we're almost at our destination. It's similar to how the wind at an entrance becomes stronger when there's a large pressure difference between the two connected points.","TWN":"這代表我們已經快到目的地了。這原理就跟隧道連接的兩個地點的氣壓差距越大，出入口的風就越強一樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리의 목적지는... 현실과는 전혀 다른 차원의 현실이니까.","JPN":"私たちの目的地は……現実とはまったく違う次元の現実だから。","ENG":"Because our destination... is a reality from a completely different dimension than ours.","TWN":"因為我們的目的地……是與現實完全不同次元的現實。"},"stage":{"bg":"PROLOGUE_03","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"터널 끝이 보입니다! 차원 간 돌파 준비! 이터니움 드라이브 출력을 최대치로!","JPN":"トンネルの終わりが見えました！　次元間突破準備！　エタニウムドライブの出力を最大値に！","ENG":"I can see the end of the tunnel! Prepare for interdimensional breakthrough! Eternium Drive output to maximum!","TWN":"看見隧道出口了！準備突破次元！永恆之金引擎輸出最大！"},"stage":{"bg":"PROLOGUE_03","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"달의 부적 기운 최대치, 요정의 가호력 최대치! 무사고- 안전제일- 대박기원!!","JPN":"お月様のお守りの力、最大値。妖精様の加護の力、最大値！　無事故、安全第一、大当たり祈願！！","ENG":"Moon charm energy at maximum, fairy's blessing power at maximum! No accidents! Safety first! Wishing for great luck!!","TWN":"月之護符能量最大，精靈加護最大！零事故—安全第一－祈願大成功！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"전 승무원! 크게 흔들릴 테니 꽉 잡아!","JPN":"全乗務員！　揺れが大きくなるからしっかり捕まって！","ENG":"Everyone! It's going to shake hard, so hold on tight!","TWN":"全體船員！艦船會劇烈晃動，抓緊了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_FIRE_ENERGY_SMALL_04"},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"빠져나온... 건가? 같이 온 다른 함선들은 어디 있지?","JPN":"抜けた……のか？　一緒に来た他の艦船は？","ENG":"Did we... make it out? Where are the other ships that came with us?","TWN":"成功……脫離了嗎？其他一起來的艦船呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"통신과 탐지 장비가 작동을 멈춰서 모르겠어요. 안개가 너무 짙어서 육안으로도 확인이 불가능합니다.","JPN":"通信装備も探知装備も止まってしまったせいでよく分かりません。霧が濃すぎて、肉眼での確認も不可能です。","ENG":"Comms and detection equipment have stopped working, so I don't know. The fog is too thick to confirm anything visually either.","TWN":"通訊和探測設備都停止運作了。不只如此，霧太濃了，用肉眼也看不清。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"안개가 아니야.","JPN":"霧じゃない。","ENG":"It's not fog.","TWN":"那不是霧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이건 아마도, 눈보라...","JPN":"これは多分、吹雪……","ENG":"This is probably... a snowstorm...","TWN":"那恐怕是暴風雪……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"...큭!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……呃！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"특이 에너지 관측! 패턴은...","JPN":"特異エネルギー観測！　パターンは……","ENG":"Unusual energy detected! The pattern is...","TWN":"觀測到異常能量！模式是……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"...신성 반응?","JPN":"……神聖反応？","ENG":"...A Divinity response?","TWN":"……神性反應？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마, 세피라의 수호자인가?","JPN":"まさか、セフィラの守護者なの？","ENG":"Could it be the Guardian of Sephira?","TWN":"難道是塞菲拉守護者？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건 아닐 겁니다.","JPN":"それは違うと思います。","ENG":"That's unlikely.","TWN":"應該不是。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"신성의 찌꺼기에 불과한 수호자는, 존재만으로 영향력을 주지 못하거든요.","JPN":"神聖の残りカスにすぎない守護者は、その存在だけでは影響力を持ちません。","ENG":"A guardian that's nothing more than a remnant of Divinity wouldn't be able to exert influence just by existing.","TWN":"只是神性殘渣形成的守護者，光是存在本身並不會造成這種影響。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"뭐지? 눈보라가 걷힐수록... 오히려 눈 뜨기가 힘들어지는데?","JPN":"なんだろう？　吹雪が晴れてくるほど……逆に目が開けづらくなってくるんだけど？","ENG":"What is this? The more the snowstorm clears... the harder it becomes to open my eyes.","TWN":"怎麼回事？暴風雪越散開……眼睛反而越睜不開？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_HATE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"빛에... 끌려가는 기분이네.","JPN":"光に……引っ張られる感じだね。","ENG":"It feels like I'm being drawn toward the light.","TWN":"有種……被光吸走的感覺。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_HATE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭...!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"嘖…！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"미나야! 괜찮아?","JPN":"ミナ！　大丈夫？","ENG":"Mina! Are you okay?","TWN":"米娜！你沒事吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배!","JPN":"ミナ先輩！","ENG":"Mina!","TWN":"米娜前輩！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...뭔가 머리에 대고 속삭이는 것 같아서, 지끈거려.","JPN":"……何かが頭に直接響いてくるみたいで、ズキズキする。","ENG":"...It feels like something is whispering directly into my head. It hurts.","TWN":"……感覺好像有人貼在我腦袋旁邊低語，頭好痛。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런가.","JPN":"そうか。","ENG":"I see.","TWN":"是嗎。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"신성과 교감 할 수 있음에도 평범한 인간의 몸을 가졌으니, 고통으로 다가오는 거군.","JPN":"神聖と交感できるとはいえ、肉体は普通の人間。だから苦痛に感じるんだな。","ENG":"Even though you can resonate with Divinity, you still have the body of an ordinary human, so it manifests as pain.","TWN":"雖然能與神性產生共鳴，卻擁有普通人的身體，所以才會痛苦。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"교감... 이라고? 이딴 게?","JPN":"交感……？　こんなものが？","ENG":"Resonate...? With this?","TWN":"共鳴……？這種狀況？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"요정이라면 몰라도, 너에겐 잡음으로 밖에 들리지 않을 거다.","JPN":"妖精ならまだしも、お前には雑音にしか聞こえないだろう。","ENG":"Unless you're a fairy, it would only sound like noise to you.","TWN":"若是精靈還好，但對你來說只會聽成雜訊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이렇게 강렬한 위압감을 내뿜는 신성체는 나도 오래간만이군.","JPN":"ここまで強烈な威圧感を放つ神聖体に遭遇するのは、私も久しぶりだな。","ENG":"It's been a long time since I've seen a Divinity entity emitting pressure this intense.","TWN":"我也很久沒見過能釋放出如此強烈壓迫感的神性體了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아무래도, 저희가 하늘에 떠있는 걸 별로 좋아하지 않는 것 같아요.","JPN":"どうやら、僕たちが宙に浮いていることが気に入らないようです。","ENG":"It doesn't seem to like that we're floating in the sky very much.","TWN":"看來它似乎不太喜歡我們待在空中。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...그래. 곧 떨어질 테니 단단히 준비해둬라.","JPN":"……ああ。もうすぐ落ちるだろうから、しっかり備えておけ。","ENG":"...Right. We'll be falling soon, so brace yourselves.","TWN":"……是啊。很快就會墜落了，先做好準備吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"떨어져요...? 그게 무슨?","JPN":"落ちる……？　それはどういう……？","ENG":"Falling...? What do you mean?","TWN":"墜落……？那是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"엔진, 플레임 아웃! 이터니움 드라이브 완전 정지!","JPN":"エンジン、フレームアウト！　エタニウムドライブ完全停止！","ENG":"Engine flameout! Eternium Drive completely stopped!","TWN":"引擎熄火！永恆之金引擎完全停止！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"추력 상실! 비상 동력도 끊어졌어! 그 신성이란 거, 방해전파처럼 작동하는 것 같아!","JPN":"推力喪失！　非常動力も切れちゃったよ！　その神聖ってやつ、ジャミングのように作用するみたい！","ENG":"We've lost thrust! Even the emergency power's gone! That Divinity seems to be acting like interference waves!","TWN":"失去推力！連緊急動力也切斷了！那個神性體像干擾波一樣在影響系統！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"함대 전체가... 추락합니다!","JPN":"全艦隊……墜落します！","ENG":"The entire fleet... is crashing!","TWN":"整個艦隊……正在墜落！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐? 이 높이에서?!","JPN":"え？　この高さから！？","ENG":"What? From this height?!","TWN":"什麼？這種高度？！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서윤, 염동력으로 어떻게 해볼 순 없을까?","JPN":"シズカ、念動力でなんとかできない？","ENG":"Seo Yoon, can't you do something with your telekinesis?","TWN":"徐芸，能用念力做點什麼嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"이 상황에 날 찾아줘서 고맙긴 한데, 내가 차원함선을 어떻게 해볼 정도의 괴물은 아니거든?","JPN":"この状況で頼ってくれるのは嬉しいけど、私も次元艦船をどうこうできるほどの化け物じゃないの。","ENG":"I appreciate that you thought of me in this situation, but I'm not some kind of big shot who can handle a dimensional ship.","TWN":"我很謝謝你在這種時候找我，但我還沒厲害到能操控次元艦船這種怪物啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"이미 전력으로 시도해보는 중이지만...! 꿈쩍도 안 해!","JPN":"もう全力で試してるけど……！　びくともしない！","ENG":"I'm already trying with everything I've got... but it won't budge!","TWN":"我已經在全力嘗試了……！但完全動不了！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"곤란하군요. 함선의 동력이 사라지면 마리아 중장의 가르강튀아도 제 기능을 발휘하지 못할 텐데요.","JPN":"困りましたね。艦船の動力が消えたら、マリア中将のガルガンティアも使えないはずです。","ENG":"This is a problem. If the ship loses power, Lieutenant General Maria's Garguantia won't be able to function properly either.","TWN":"這下麻煩了。若艦船失去動力，瑪麗亞中將的加爾剛迪亞也無法發揮作用。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...류드밀라. 함대 중 자네가 감당할 수 있는 수는 얼마나 되지?","JPN":"……リュドミラ。君がフォローできる艦隊の数はどれくらいかね。","ENG":"...Lyudmila. How many ships in the fleet can you handle?","TWN":"……盧德米拉，在艦隊裡你最多能承擔多少？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"신성의 간섭 때문에 제가 오래 머물 순 없겠군요.","JPN":"神聖の干渉のせいで、長居できそうにありません。","ENG":"Because of the Divinity interference, I won't be able to remain for long.","TWN":"因為受到神性干擾，我無法長時間停留。"},"stage":{"bg":"VOID","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_17"},{"id":"L4_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"...한 척을 제외하면, 모두 최소한의 피해로 착륙 시킬 수 있을 겁니다.","JPN":"……1隻を除けば、全艦、被害を最低限に押さえて着陸させられます。","ENG":"...Except for one ship, I should be able to land them all with minimal damage.","TWN":"……除了其中一艘，其餘都能以最低損傷降落。"},"stage":{"bg":"VOID","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"알겠네.","JPN":"分かった。","ENG":"Understood.","TWN":"我明白了。"},"stage":{"bg":"VOID","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면, 코핀함을 제외한 모든 함대를 도와주게.","JPN":"では、コフィン艦を除く全艦隊を助けてくれたまえ。","ENG":"Then assist all ships except Coffin.","TWN":"那麼，除了科芬艦之外，其餘艦隊就交給你了。"},"stage":{"bg":"VOID","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VOID","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"맡겨주십시오.","JPN":"お任せください。","ENG":"Got it.","TWN":"交給我吧。"},"stage":{"bg":"VOID","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"벌써, 그 카드를 쓰시려는 건가요?","JPN":"もう、あの手を使うおつもりですか？","ENG":"You're already planning to use that card?","TWN":"已經……要動用那張王牌了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 사전에 패를 아끼다 손해를 보는 건... 하책 중의 하책이라서 말이야.","JPN":"切り札を使うのを躊躇って損をするのは……下策中の下策だからね。","ENG":"In my book, holding back a card and taking a loss because of it... is the worst possible move.","TWN":"我一直都認為，為了保留底牌而吃虧……是下策中的下下策。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"살려주세요, 요정님! 구해주시면 지금까지 모은 전재산 전부 바칠게요오!","JPN":"お助けください、妖精様！　お助けくだされば、今まで集めた私の全財産を捧げますからああ！","ENG":"Please save us, Fairy Godmother! If you help us, I'll give you my entire fortune!","TWN":"救命啊，精靈大人！只要救我，我願意獻上累積到現在的所有財產！"},"stage":{"bg":"BLACK","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"...어라?","JPN":"……あれ？","ENG":"...Huh?","TWN":"……咦？"},"stage":{"bg":"BLACK","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_AIR_SMALL_START"},{"id":"L20_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"추락하는 속도가 제법 느려지지 않았나요?","JPN":"落ちるスピード、かなり遅くなってませんか？","ENG":"Hasn't our falling speed slowed down quite a bit?","TWN":"下降的速度好像變慢了？"},"stage":{"bg":"BLACK","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그러게요. 이 정도 속도라면, 안전벨트를 맨 보람이 있겠어요.","JPN":"そうですね。このスピードなら、シートベルトを締める意味がありそうです。","ENG":"You're right. At this speed, I'm glad I put on my seatbelt.","TWN":"真的耶。這種速度讓繫安全帶總算有點意義了。"},"stage":{"bg":"BLACK","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 된 거죠? 차원함선이 무동력 비행이 가능하단 얘긴 들어본 적 없는데?","JPN":"どういうことですか？　次元艦船に無動力飛行ができるという話は聞いていませんが。","ENG":"What's going on? I've never heard of a dimensional ship being able to glide without power.","TWN":"怎麼回事？我可沒聽說過次元艦船能無動力飛行。"},"stage":{"bg":"BLACK","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"설마, 정말로 요정님이 도와준 건가?","JPN":"まさか、本当に妖精様が助けてくれた？","ENG":"Could it be... the Fairy Godmother really helped us?","TWN":"難道……真的有精靈來幫忙？"},"stage":{"bg":"BLACK","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"요정은 아닙니다만, 당신의 전재산은 유감 없이 받아가도록 하겠습니다.","JPN":"妖精ではありませんが、あなたの全財産は遠慮せずいただきます。","ENG":"I'm not a fairy, but I will gratefully accept your entire fortune.","TWN":"雖然不是精靈，但我會毫不客氣收下你所有財產。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"엑. 누구죠?","JPN":"えっ、どなたですか？","ENG":"Huh? Who's that?","TWN":"欸？你是誰？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"호라이즌 파이낸스의 호라이즌 사장일세. 얼마 전 코핀 컴퍼니와 협력사 계약을 맺었지.","JPN":"ホライズン・ファイナンスのホライズン社長だ。少し前にコフィンカンパニーとパートナーシップ契約を締結したんだ。","ENG":"It's Horizon of Horizon Finance. Not long ago, we signed a partnership agreement with Coffin Company.","TWN":"我是地平線金融的老闆，地平線。前陣子才和科芬公司簽了合作協議。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"파이낸스...? 저희 회사 대출 받았나요?","JPN":"ファイナンス……？　うちの会社、借金してるんですか？","ENG":"Finance...? Did our company take out a loan?","TWN":"金融……？我們公司有借錢嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"돈 대신 인력을 빌렸습니다.","JPN":"お金ではなく人を借りています。","ENG":"We borrowed manpower instead of money.","TWN":"不是借錢，是借人。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시국이 시국인 만큼, 용병은 많을수록 좋으니까요.","JPN":"状況が状況なだけに、傭兵は多ければ多いほどいいですからね。","ENG":"Given the current situation, the more mercenaries we have, the better.","TWN":"在這種局勢下，傭兵當然越多越好。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"비상 착륙... 성공입니다.","JPN":"非常着陸……成功です。","ENG":"Emergency landing... successful.","TWN":"緊急迫降……成功。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"전력이 돌아온 걸 보니, 지상 쪽은 신성 파장의 영향을 덜 받는 것 같아요.","JPN":"電力が復活したところを見ると、地上のほうは神聖波長の影響が弱いようです。","ENG":"Now that power's back online, it seems the ground is less affected by the Divinity wavelength.","TWN":"電力恢復了，看來地面似乎比較不受神性波動影響。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"지상에서 함선이 할 수 있는 역할은 몇 가지 없겠지만... 집에 돌아갈 방법이 남아있단 건 그나마 다행이군.","JPN":"地上で艦船にできることはそうないだろうが……家に戻る手段が残ってるのは不幸中の幸いだな。","ENG":"There's not much a ship can do from the ground... But it's still a relief that we still have a way to return home.","TWN":"雖然艦船在地面能做的事不多……但至少還有回去的方法，也算不幸中的大幸。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"현문 및 램프도어를 개방합니다! 안전을 확인 후 내려주세요!","JPN":"舷門及びランプドアを開放します！　安全を確認してから下船してください！","ENG":"Opening the hatch and ramp door! Please disembark after confirming safety!","TWN":"開啟舷門與艙門！確認安全後下船！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"여기구나. 마왕 타기리온에게 가는 길이.","JPN":"これだね、魔王タギリオンに続く道は。","ENG":"This is it. The path that leads to Demon Lord Thagirion.","TWN":"通往魔王塔基里翁的路就是這裡啊。"},"stage":{"bg":"PATH","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"겨울이네요. 온 사방이 눈으로 덮여있어요.","JPN":"冬ですね。一帯が雪に覆われています。","ENG":"It's winter. Everything's covered in snow.","TWN":"是冬天呢，到處都被雪覆蓋。"},"stage":{"bg":"PATH","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러게.","JPN":"そうだね。","ENG":"Yeah.","TWN":"是啊。"},"stage":{"bg":"PATH","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...아.","JPN":"……あ。","ENG":"...Ah.","TWN":"……啊。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"도와줘서 고마워, 호라이즌 씨.","JPN":"助けてくれてありがとう、ホライズンさん。","ENG":"Thank you for your help, Ms. Horizon.","TWN":"地平線，謝謝你救了我。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"별 말씀을. 계약에 따랐을 뿐입니다.","JPN":"どういたしまして。契約を履行したまでです。","ENG":"Not at all. I simply followed the contract.","TWN":"不用客氣，我只是履行契約罷了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"하지만 잡담을 나눌 여유는 없어 보이는군요.","JPN":"ですが、雑談を交わしている余裕はなさそうです。","ENG":"But it doesn't seem like we have time for small talk.","TWN":"不過看來現在似乎沒時間閒聊了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"침식체... 엄청난 숫자지만, 마왕의 영역 근처라면 이상할 것도 없지.","JPN":"侵食体……おびただしい数だけど、魔王の領域の近くならおかしくはないよね。","ENG":"C.O.s... There are an overwhelming number of them, but near the Demon Lord's domain, that's to be expected.","TWN":"雖然侵蝕體……數量驚人，但既然在魔王領域附近，會這樣也不奇怪。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"동기화 절차를 생략한 무리한 가동으로, 전 잠시 동안 비동력 상태로 전환해야 합니다.","JPN":"同期化手続きを省略して無理に稼働したため、私はしばらく非動力状態に切り替えなければなりません。","ENG":"Because I forced operation without completing synchronization procedures, I'll need to switch to a non-powered state for a while.","TWN":"因為強行啟動又跳過同步程序，我暫時得進入無動力狀態。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까... 쉴 시간이 필요하다는 거지?","JPN":"つまり……休む時間が必要ってことだね？","ENG":"So... you need some time to rest, right?","TWN":"也就是說……需要休息一下？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"걱정 마. 이 앞은 우리가 맡을게.","JPN":"大丈夫。この先は私たちに任せて。","ENG":"Don't worry. We'll handle what's ahead.","TWN":"放心，前面交給我們。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"다이애나 씨. 침식체들을 무력화할 수단을 가져왔다고 하지 않았나요?","JPN":"ダイアナさん、侵食体を無力化する手段があるとおっしゃってましたよね。","ENG":"Ms. Diana. Didn't you say you brought a method to neutralize the C.O.s?","TWN":"黛安娜，你不是說帶了能壓制侵蝕體的東西嗎？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"미안하지만 아까 함선이 추락한 뒤로 침식파 때문에 신호가 안 잡혀.","JPN":"悪いが、さっき艦船が落ちてから侵食波のせいで信号が受信できないんだ。","ENG":"I'm sorry, but after the ship crashed earlier, I can't get a signal because of the Corruption rays.","TWN":"抱歉，剛才墜落後被侵蝕波干擾，現在收不到訊號。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"주변에 침식균열 몇 개가 감지됐는데, 그것만 닫을 수 있어도 내 걸 가동할 수 있을 거야.","JPN":"近くに侵食亀裂が幾つか感知されているが、それさえ塞げれば、私のを稼働できると思う。","ENG":"Several Corruption rifts have been detected nearby. If we can close just those, I should be able to activate mine.","TWN":"附近偵測到幾個侵蝕裂縫，只要能關閉它們，就能啟動我的裝置。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"침식 균열은 나도 거슬리긴 하다만, 거기까지 신경 쓸 여유는 없어.","JPN":"侵食亀裂も気になってはいるが、そこまで手を回す余裕はない。","ENG":"The Corruption rifts are bothering me as well, but we don't have the time to deal with them.","TWN":"雖然我也很在意那些裂縫，但現在沒有餘力處理。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우리 목표는 저 산 꼭대기에서 빛을 뿜는 신성체다. 저곳에 타기리온이 숨어있을 거야.","JPN":"私たちの目標はあの山の頂上で光を放つ神聖体だ。あそこにタギリオンが隠れているはずだからな。","ENG":"Our objective is the Divinity entity emitting light from the top of that mountain. Thagirion should be hiding there.","TWN":"我們的目標是山頂那個發光的神性體，塔基里翁應該就躲在那裡。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어쩌면... 그 녀석의 왕좌가 있을지도 모르겠군.","JPN":"もしかすると……やつの玉座があるかもしれない。","ENG":"Perhaps... her throne may be there as well.","TWN":"說不定……那裡就是她的王座。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"가야 할 길이 꽤 먼 것 같네요.","JPN":"まだ先は遠いですね。","ENG":"It looks like we still have quite a long way to go.","TWN":"看來我們還要走很遠的路。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"등산 같은 건, 사내 워크숍이 아니면 할 일이 없을 줄 알았는데 말이죠.","JPN":"登山なんて、社内ワークショップ以外ですることはないと思ってましたが。","ENG":"I didn't think I'd ever go hiking unless it was a company workshop.","TWN":"本來以為只有公司團建才會遇到爬山這種事。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부사장... 주말에 직원들 데리고 산 탔나?","JPN":"副社長……週末に社員たちを連れて山に登っていたのか。","ENG":"Vice President... did you take the employees hiking on the weekend?","TWN":"副總……你週末帶員工去爬山嗎？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 적 없습니다.","JPN":"登っていません。","ENG":"Not even once.","TWN":"從來沒有過。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"올라가자.","JPN":"行こう。","ENG":"Let's go.","TWN":"上去吧。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마왕 타기리온을 만나러.","JPN":"魔王タギリオンに会いに。","ENG":"To meet Demon Lord Thagirion.","TWN":"去見魔王塔基里翁。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};